#include <stdio.h>
#include <stdlib.h>

typedef struct { long long w; long long v; double r; } Item;

int cmp(const void *a, const void *b) {
    const Item *ia = (const Item *)a;
    const Item *ib = (const Item *)b;
    if (ib->r > ia->r) return 1;
    if (ib->r < ia->r) return -1;
    return 0;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        long long Wmax;
        scanf("%d %lld", &N, &Wmax);
        Item *items = (Item *)malloc(N * sizeof(Item));
        for (int i = 0; i < N; ++i) {
            scanf("%lld %lld", &items[i].w, &items[i].v);
            items[i].r = (double)items[i].v / (double)items[i].w;
        }
        qsort(items, N, sizeof(Item), cmp);
        double total = 0.0;
        long long remaining = Wmax;
        for (int i = 0; i < N; ++i) {
            if (items[i].w <= remaining) {
                total += items[i].v;
                remaining -= items[i].w;
            } else {
                total += items[i].v * ((double)remaining / (double)items[i].w);
                break;
            }
        }
        printf("%.2f\n", total);
        free(items);
    }
    return 0;
}

