code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static class Item {
        long w, v;
        double r;
        Item(long w, long v) { this.w = w; this.v = v; this.r = (double) v / (double) w; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            long Wmax = Long.parseLong(st.nextToken());
            Item[] items = new Item[N];
            for (int i = 0; i < N; ++i) {
                st = new StringTokenizer(br.readLine());
                long w = Long.parseLong(st.nextToken());
                long v = Long.parseLong(st.nextToken());
                items[i] = new Item(w, v);
            }
            Arrays.sort(items, (a, b) -> Double.compare(b.r, a.r));
            double total = 0.0;
            long remaining = Wmax;
            for (Item it : items) {
                if (it.w <= remaining) {
                    total += it.v;
                    remaining -= it.w;
                } else {
                    total += it.v * ((double) remaining / (double) it.w);
                    break;
                }
            }
            sb.append(String.format(java.util.Locale.US, "%.2f", total)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

